   /**
         * 把秒数转化为天、时、分、秒
         * 参数value是秒数
         */
  export const formatSeconds = (value:any) => {
    let secondTime = parseInt(value)  // 秒
    let minuteTime = 0 // 分
    let hourTime = 0 // 小时
    let dayTime = 0 // 天
    let result = ''
    if (value < 60) {
        result = secondTime + '秒'
    } else {
        if (secondTime >= 60) { // 如果秒数大于60，将秒数转换成整数
            // 获取分钟，除以60取整数，得到整数分钟
            minuteTime = parseInt(secondTime / 60  as any) 
            // 获取秒数，秒数取佘，得到整数秒数
            secondTime = parseInt(secondTime % 60  as any)
            // 如果分钟大于60，将分钟转换成小时
            if (minuteTime >= 60) {
                // 获取小时，获取分钟除以60，得到整数小时
                hourTime = parseInt(minuteTime / 60  as any)
                // 获取小时后取佘的分，获取分钟除以60取佘的分
                minuteTime = parseInt(minuteTime % 60  as any)
                if (hourTime >= 24) {
                    // 获取天数， 获取小时除以24，得到整数天
                    dayTime = parseInt(hourTime / 24  as any)
                    // 获取小时后取余小时，获取分钟除以24取余的分；
                    hourTime = parseInt(hourTime % 24  as any)
                }
            }
        }
        if (secondTime > 0) {
            secondTime = parseInt(secondTime  as any) >= 10 ? secondTime : '0' + secondTime  as any
            result = '' + secondTime + '秒'
        }
        if (minuteTime > 0) {
            minuteTime = parseInt(minuteTime  as any) >= 10 ? minuteTime : '0' + minuteTime  as any
            result = '' + minuteTime + '分' + result
        }
        if (hourTime > 0) {
            result = '' + parseInt(hourTime  as any) + '小时' + result  as any
        }
        if (dayTime > 0) {
            result = '' + parseInt(dayTime  as any) + '天' + result  as any
        }
    }
    return result
}
// 比较app版本号
export function compareVersion(version1: string, version2: string) {
  const v1 = version1.split('.');
  const v2 = version2.split('.');
  for (let i = 0; i < v1.length || i < v2.length; i++) {
      let x = 0, y = 0;
      if (i < v1.length) {
          x = parseInt(v1[i]);
      }
      if (i < v2.length) {
          y = parseInt(v2[i])
      }
      if (x > y) return 1;
      if (x < y) return -1;
  }
  return 0;
}

