// message.js
import { createApp } from "vue";
import Message from "./index.vue";

interface Option {
    title?: string;
    content?: string;
    props: any;
}

function mountContent(option: string | Option, showImg?: string, noAuto?: boolean) {
    const options = typeof option === "string"
        ? {
            props: {
                msg: option,
                img: showImg || ""
            }
        } : option;
    const app = createApp(Message, options.props);

    app.mount("#message");
    if (!noAuto) {
        setTimeout(() => app.unmount(), 3000);
    }
    return app;
}
export default mountContent;
