import * as Sentry from '@sentry/vue';
import { Integrations } from '@sentry/tracing';
import router from '@/router';
import {
	env,
} from '../config/env';

// eslint-disable-next-line @typescript-eslint/explicit-module-boundary-types, @typescript-eslint/no-explicit-any
export default function SentryInit (app:any){
    if (env !== 'dev') {
        Sentry.init({
            app,
            dsn: 'https://15408c7f546e4138a0efb95b61f6d01e@sentry.tipaipai.com//75',
            autoSessionTracking: true,
            integrations: [
                new Integrations.BrowserTracing({
                    routingInstrumentation: Sentry.vueRouterInstrumentation(router),
                }),
            ],
            tracesSampleRate: 1.0,
            // release: `${process.env.VUE_APP_SENTRY_PROJECT}_${process.env.VUE_APP_SENTRY_RELEASE_VERSION}`,
            environment: env,
        });
        Sentry.configureScope((scope) => {
            scope.setExtra("userAgent", navigator.userAgent);
        });
    }
}